function Pathology() {
  return (
    <div style={{ padding: "2rem" }}>
      <h2>Pathology Services</h2>
      <p>
        Here you can explore diagnostic centers, book tests, and get accurate
        lab reports quickly.
      </p>
    </div>
  );
}

export default Pathology;
